import React, { useState } from 'react';
import { Package, Send, MapPin, Search, User, Calendar, DollarSign, Clock, CheckCircle, XCircle, Truck } from 'lucide-react';

export default function PostOfficeApp() {
  const [activeTab, setActiveTab] = useState('track');
  const [trackingNumber, setTrackingNumber] = useState('');
  const [searchResult, setSearchResult] = useState(null);

  const sampleParcels = [
    { id: 'PKG001', sender: 'Rajesh Kumar', receiver: 'Priya Sharma', status: 'In Transit', from: 'Delhi', to: 'Mumbai', weight: '2.5kg', cost: '₹150' },
    { id: 'PKG002', sender: 'Amit Singh', receiver: 'Neha Verma', status: 'Delivered', from: 'Bangalore', to: 'Pune', weight: '1.2kg', cost: '₹100' },
    { id: 'PKG003', sender: 'Suresh Patel', receiver: 'Kavita Joshi', status: 'Pending', from: 'Ahmedabad', to: 'Surat', weight: '3.0kg', cost: '₹200' }
  ];

  const [parcels, setParcels] = useState(sampleParcels);
  const [newParcel, setNewParcel] = useState({
    sender: '',
    receiver: '',
    from: '',
    to: '',
    weight: '',
    cost: ''
  });

  const handleTrack = () => {
    const found = parcels.find(p => p.id === trackingNumber.toUpperCase());
    setSearchResult(found || { error: 'Parcel not found' });
  };

  const handleAddParcel = () => {
    if (!newParcel.sender || !newParcel.receiver || !newParcel.from || !newParcel.to || !newParcel.weight || !newParcel.cost) {
      alert('Please fill all fields');
      return;
    }

    const newId = `PKG${String(parcels.length + 1).padStart(3, '0')}`;
    const parcel = {
      id: newId,
      ...newParcel,
      status: 'Pending'
    };
    setParcels([...parcels, parcel]);
    setNewParcel({ sender: '', receiver: '', from: '', to: '', weight: '', cost: '' });
    alert(`Parcel registered successfully! Tracking ID: ${newId}`);
  };

  const getStatusIcon = (status) => {
    switch(status) {
      case 'Delivered': return <CheckCircle className="text-success" size={20} />;
      case 'In Transit': return <Truck className="text-primary" size={20} />;
      case 'Pending': return <Clock className="text-warning" size={20} />;
      default: return <XCircle className="text-danger" size={20} />;
    }
  };

  const getStatusBadge = (status) => {
    switch(status) {
      case 'Delivered': return 'success';
      case 'In Transit': return 'primary';
      case 'Pending': return 'warning';
      default: return 'danger';
    }
  };

  return (
    <div style={{ minHeight: '100vh', background: 'linear-gradient(135deg, #e3f2fd 0%, #c5cae9 100%)' }}>
      <link
        href="https://cdn.jsdelivr.net/npm/bootstrap@5.3.0/dist/css/bootstrap.min.css"
        rel="stylesheet"
      />

      {/* Header */}
      <header className="bg-primary text-white shadow-lg">
        <div className="container py-4">
          <div className="d-flex justify-content-between align-items-center">
            <div className="d-flex align-items-center">
              <Package size={36} className="me-3" />
              <div>
                <h1 className="h2 mb-0">Dakkhana</h1>
                <p className="mb-0 small opacity-75">Post Office Management System</p>
              </div>
            </div>
            <div className="d-flex align-items-center">
              <User size={24} className="me-2" />
              <span>Admin</span>
            </div>
          </div>
        </div>
      </header>

      {/* Navigation Tabs */}
      <div className="container mt-4">
        <div className="card shadow-sm">
          <div className="card-body p-2">
            <div className="d-flex gap-2">
              <button
                onClick={() => setActiveTab('track')}
                className={`btn flex-fill d-flex align-items-center justify-content-center gap-2 ${
                  activeTab === 'track' ? 'btn-primary' : 'btn-light'
                }`}
              >
                <Search size={20} />
                <span>Track Parcel</span>
              </button>
              <button
                onClick={() => setActiveTab('register')}
                className={`btn flex-fill d-flex align-items-center justify-content-center gap-2 ${
                  activeTab === 'register' ? 'btn-primary' : 'btn-light'
                }`}
              >
                <Send size={20} />
                <span>Register Parcel</span>
              </button>
              <button
                onClick={() => setActiveTab('list')}
                className={`btn flex-fill d-flex align-items-center justify-content-center gap-2 ${
                  activeTab === 'list' ? 'btn-primary' : 'btn-light'
                }`}
              >
                <Package size={20} />
                <span>All Parcels</span>
              </button>
            </div>
          </div>
        </div>
      </div>

      {/* Main Content */}
      <div className="container py-4">
        {/* Track Parcel Tab */}
        {activeTab === 'track' && (
          <div className="card shadow-sm">
            <div className="card-body p-4">
              <h2 className="card-title mb-4">Track Your Parcel</h2>
              <div className="row g-3 mb-4">
                <div className="col">
                  <input
                    type="text"
                    placeholder="Enter Tracking Number (e.g., PKG001)"
                    value={trackingNumber}
                    onChange={(e) => setTrackingNumber(e.target.value)}
                    className="form-control form-control-lg"
                  />
                </div>
                <div className="col-auto">
                  <button
                    onClick={handleTrack}
                    className="btn btn-primary btn-lg d-flex align-items-center gap-2"
                  >
                    <Search size={20} />
                    <span>Track</span>
                  </button>
                </div>
              </div>

              {searchResult && (
                <div className="card mt-4 bg-light">
                  <div className="card-body">
                    {searchResult.error ? (
                      <div className="d-flex align-items-center text-danger">
                        <XCircle size={24} className="me-2" />
                        <span className="h5 mb-0">{searchResult.error}</span>
                      </div>
                    ) : (
                      <div>
                        <div className="d-flex justify-content-between align-items-center mb-4">
                          <h3 className="h5 mb-0">Tracking ID: {searchResult.id}</h3>
                          <span className={`badge bg-${getStatusBadge(searchResult.status)} d-flex align-items-center gap-2 fs-6`}>
                            {getStatusIcon(searchResult.status)}
                            {searchResult.status}
                          </span>
                        </div>
                        <div className="row g-4">
                          <div className="col-md-6">
                            <div className="d-flex align-items-center">
                              <User size={18} className="text-secondary me-2" />
                              <div>
                                <p className="text-secondary mb-1 small">Sender</p>
                                <p className="fw-bold mb-0">{searchResult.sender}</p>
                              </div>
                            </div>
                          </div>
                          <div className="col-md-6">
                            <div className="d-flex align-items-center">
                              <User size={18} className="text-secondary me-2" />
                              <div>
                                <p className="text-secondary mb-1 small">Receiver</p>
                                <p className="fw-bold mb-0">{searchResult.receiver}</p>
                              </div>
                            </div>
                          </div>
                          <div className="col-md-6">
                            <div className="d-flex align-items-center">
                              <MapPin size={18} className="text-secondary me-2" />
                              <div>
                                <p className="text-secondary mb-1 small">From</p>
                                <p className="fw-bold mb-0">{searchResult.from}</p>
                              </div>
                            </div>
                          </div>
                          <div className="col-md-6">
                            <div className="d-flex align-items-center">
                              <MapPin size={18} className="text-secondary me-2" />
                              <div>
                                <p className="text-secondary mb-1 small">To</p>
                                <p className="fw-bold mb-0">{searchResult.to}</p>
                              </div>
                            </div>
                          </div>
                          <div className="col-md-6">
                            <div className="d-flex align-items-center">
                              <Package size={18} className="text-secondary me-2" />
                              <div>
                                <p className="text-secondary mb-1 small">Weight</p>
                                <p className="fw-bold mb-0">{searchResult.weight}</p>
                              </div>
                            </div>
                          </div>
                          <div className="col-md-6">
                            <div className="d-flex align-items-center">
                              <DollarSign size={18} className="text-secondary me-2" />
                              <div>
                                <p className="text-secondary mb-1 small">Cost</p>
                                <p className="fw-bold mb-0">{searchResult.cost}</p>
                              </div>
                            </div>
                          </div>
                        </div>
                      </div>
                    )}
                  </div>
                </div>
              )}
            </div>
          </div>
        )}

        {/* Register Parcel Tab */}
        {activeTab === 'register' && (
          <div className="card shadow-sm">
            <div className="card-body p-4">
              <h2 className="card-title mb-4">Register New Parcel</h2>
              <div className="row g-3">
                <div className="col-md-6">
                  <label className="form-label fw-medium">Sender Name</label>
                  <input
                    type="text"
                    value={newParcel.sender}
                    onChange={(e) => setNewParcel({...newParcel, sender: e.target.value})}
                    className="form-control"
                    placeholder="Enter sender name"
                  />
                </div>
                <div className="col-md-6">
                  <label className="form-label fw-medium">Receiver Name</label>
                  <input
                    type="text"
                    value={newParcel.receiver}
                    onChange={(e) => setNewParcel({...newParcel, receiver: e.target.value})}
                    className="form-control"
                    placeholder="Enter receiver name"
                  />
                </div>
                <div className="col-md-6">
                  <label className="form-label fw-medium">From (City)</label>
                  <input
                    type="text"
                    value={newParcel.from}
                    onChange={(e) => setNewParcel({...newParcel, from: e.target.value})}
                    className="form-control"
                    placeholder="Source city"
                  />
                </div>
                <div className="col-md-6">
                  <label className="form-label fw-medium">To (City)</label>
                  <input
                    type="text"
                    value={newParcel.to}
                    onChange={(e) => setNewParcel({...newParcel, to: e.target.value})}
                    className="form-control"
                    placeholder="Destination city"
                  />
                </div>
                <div className="col-md-6">
                  <label className="form-label fw-medium">Weight</label>
                  <input
                    type="text"
                    value={newParcel.weight}
                    onChange={(e) => setNewParcel({...newParcel, weight: e.target.value})}
                    className="form-control"
                    placeholder="e.g., 2.5kg"
                  />
                </div>
                <div className="col-md-6">
                  <label className="form-label fw-medium">Cost</label>
                  <input
                    type="text"
                    value={newParcel.cost}
                    onChange={(e) => setNewParcel({...newParcel, cost: e.target.value})}
                    className="form-control"
                    placeholder="e.g., ₹150"
                  />
                </div>
              </div>
              <button
                onClick={handleAddParcel}
                className="btn btn-primary mt-4 d-flex align-items-center gap-2"
              >
                <Send size={20} />
                <span>Register Parcel</span>
              </button>
            </div>
          </div>
        )}

        {/* All Parcels Tab */}
        {activeTab === 'list' && (
          <div className="card shadow-sm">
            <div className="card-body p-4">
              <h2 className="card-title mb-4">All Parcels</h2>
              <div className="table-responsive">
                <table className="table table-hover">
                  <thead className="table-light">
                    <tr>
                      <th>Tracking ID</th>
                      <th>Sender</th>
                      <th>Receiver</th>
                      <th>Route</th>
                      <th>Weight</th>
                      <th>Cost</th>
                      <th>Status</th>
                    </tr>
                  </thead>
                  <tbody>
                    {parcels.map((parcel) => (
                      <tr key={parcel.id}>
                        <td className="fw-medium text-primary">{parcel.id}</td>
                        <td>{parcel.sender}</td>
                        <td>{parcel.receiver}</td>
                        <td>{parcel.from} → {parcel.to}</td>
                        <td>{parcel.weight}</td>
                        <td>{parcel.cost}</td>
                        <td>
                          <span className={`badge bg-${getStatusBadge(parcel.status)} d-flex align-items-center gap-2`} style={{width: 'fit-content'}}>
                            {getStatusIcon(parcel.status)}
                            {parcel.status}
                          </span>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}
